function App() {
  return (
    <div className="min-h-screen flex flex-col transition-colors duration-500">
      <Navbar />

      {/* 🎯 Centralized Content Hub: Fixes alignment and margin issues */}
      <main className="flex-grow flex flex-col items-center justify-center py-12 px-6">
        <div className="w-full max-w-7xl mx-auto">
          <Routes>
            {/* Your Routes Here */}
          </Routes>
        </div>
      </main>

      {/* Optional: CRT Scanline for technical depth */}
      <div className="fixed inset-0 pointer-events-none z-[999] opacity-[0.03] bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_2px,3px_100%]" />
    </div>
  );
}

export default App;
